/* minimal-dark — default KNTIC Links theme */

*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

:root {
  --bg: #0d0d0d;
  --surface: #1a1a1a;
  --surface-hover: #252525;
  --text: #f0f0f0;
  --text-muted: #999;
  --accent: #e0e0e0;
  --border: #333;
  --radius: 8px;
  --max-width: 480px;
}

html {
  font-size: 16px;
  -webkit-text-size-adjust: 100%;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
  background-color: var(--bg);
  color: var(--text);
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 2rem 1rem 1rem;
  line-height: 1.5;
}

.profile {
  text-align: center;
  margin-bottom: 1.5rem;
  max-width: var(--max-width);
  width: 100%;
}

.profile__avatar {
  width: 88px;
  height: 88px;
  border-radius: 50%;
  object-fit: cover;
  margin-bottom: 0.75rem;
  border: 2px solid var(--border);
}

.profile__name {
  font-size: 1.25rem;
  font-weight: 600;
  margin-bottom: 0.25rem;
  color: var(--text);
}

.profile__bio {
  font-size: 0.9rem;
  color: var(--text-muted);
}

.links {
  list-style: none;
  width: 100%;
  max-width: var(--max-width);
  display: flex;
  flex-direction: column;
  gap: 0.625rem;
}

.links__item {
  display: block;
  width: 100%;
}

.links__anchor {
  display: block;
  width: 100%;
  padding: 0.875rem 1.25rem;
  background-color: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  color: var(--accent);
  text-decoration: none;
  text-align: center;
  transition: background-color 0.15s ease;
}

.links__anchor:hover,
.links__anchor:focus {
  background-color: var(--surface-hover);
  outline: none;
}

.links__label {
  font-size: 0.95rem;
  font-weight: 500;
}

.links__icon {
  margin-right: 0.4em;
}

.links__description {
  display: block;
  font-size: 0.8rem;
  color: var(--text-muted);
  margin-top: 0.2rem;
}

.footer {
  margin-top: auto;
  padding-top: 2rem;
  padding-bottom: 1rem;
  text-align: center;
}

.footer__link {
  font-size: 0.7rem;
  color: var(--text-muted);
  text-decoration: none;
  opacity: 0.6;
}

.footer__link:hover {
  opacity: 1;
}

/**
 * Static HTML page generator for KNTIC Links.
 *
 * Produces a single, fully self-contained index.html with all CSS inlined.
 * No JavaScript in the output — works with JS disabled.
 */

import { readFileSync } from 'node:fs';
import { resolve, dirname, extname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/** HTML-escape a string to prevent XSS. */
function esc(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

/** MIME type lookup for common image formats. */
function imageMime(filePath) {
  const ext = extname(filePath).toLowerCase();
  const map = {
    '.png': 'image/png',
    '.jpg': 'image/jpeg',
    '.jpeg': 'image/jpeg',
    '.gif': 'image/gif',
    '.webp': 'image/webp',
    '.svg': 'image/svg+xml',
    '.ico': 'image/x-icon',
    '.avif': 'image/avif',
  };
  return map[ext] || 'application/octet-stream';
}

/**
 * Read a local image file and return a base64 data URI.
 * @param {string} filePath — path to the image (absolute or relative to configDir)
 * @param {string} configDir — directory that links.yaml lives in
 * @returns {string} data URI string
 */
export function inlineImage(filePath, configDir) {
  const abs = resolve(configDir, filePath);
  const buf = readFileSync(abs);
  const mime = imageMime(abs);
  return `data:${mime};base64,${buf.toString('base64')}`;
}

// ---------------------------------------------------------------------------
// Schedule filtering
// ---------------------------------------------------------------------------

/**
 * Filter links to only those whose schedule window includes `now`.
 * Links without scheduling fields are always included.
 */
export function filterScheduled(links, now = new Date()) {
  if (!links || !Array.isArray(links)) return [];

  return links.filter((link) => {
    if (link.scheduled_from) {
      const from = new Date(link.scheduled_from);
      if (now < from) return false;
    }
    if (link.scheduled_until) {
      const until = new Date(link.scheduled_until);
      if (now > until) return false;
    }
    return true;
  });
}

// ---------------------------------------------------------------------------
// Theme CSS loading
// ---------------------------------------------------------------------------

/**
 * Load theme CSS from the themes directory.
 * @param {string} themeName — name without .css extension
 * @returns {string} CSS content
 */
export function loadThemeCSS(themeName) {
  const themePath = resolve(__dirname, 'themes', `${themeName}.css`);
  try {
    return readFileSync(themePath, 'utf8');
  } catch {
    throw new Error(
      `Theme "${themeName}" not found at ${themePath}. ` +
      'Available themes live in src/themes/.',
    );
  }
}

// ---------------------------------------------------------------------------
// HTML generation
// ---------------------------------------------------------------------------

/**
 * Generate a complete, self-contained HTML page from a links config.
 *
 * @param {object} config — parsed links.yaml config object
 * @param {object} [options]
 * @param {string} [options.configDir=process.cwd()] — directory links.yaml lives in (for resolving relative paths)
 * @param {Date}   [options.now=new Date()]           — current time (for schedule filtering)
 * @returns {string} Complete HTML document
 */
export function generatePage(config, options = {}) {
  const configDir = options.configDir || process.cwd();
  const now = options.now || new Date();

  const name = config.name || 'My Links';
  const bio = config.bio || '';
  const theme = config.theme || 'minimal-dark';

  // Load and inline CSS
  const css = loadThemeCSS(theme);

  // Filter links by schedule
  const links = filterScheduled(config.links, now);

  // Avatar handling
  let avatarHTML = '';
  if (config.avatar && config.avatar.trim().length > 0) {
    try {
      const dataUri = inlineImage(config.avatar, configDir);
      avatarHTML = `<img class="profile__avatar" src="${dataUri}" alt="${esc(name)}" width="88" height="88">`;
    } catch {
      // Fallback: reference the file directly (it will be copied to output dir)
      avatarHTML = `<img class="profile__avatar" src="${esc(config.avatar)}" alt="${esc(name)}" width="88" height="88">`;
    }
  }

  // Build link list HTML
  const linksHTML = links.map((link) => {
    const icon = link.icon ? `<span class="links__icon">${esc(link.icon)}</span>` : '';
    const description = link.description
      ? `<span class="links__description">${esc(link.description)}</span>`
      : '';

    return `      <li class="links__item">
        <a class="links__anchor" href="${esc(link.url)}" target="_blank" rel="noopener noreferrer">
          <span class="links__label">${icon}${esc(link.label)}</span>${description}
        </a>
      </li>`;
  }).join('\n');

  // OG description falls back to bio, then a generic string
  const ogDescription = bio || `${name} — link page`;

  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>${esc(name)}</title>
  <meta name="description" content="${esc(ogDescription)}">
  <meta property="og:title" content="${esc(name)}">
  <meta property="og:description" content="${esc(ogDescription)}">
  <meta property="og:type" content="website">
  <style>
${css}
  </style>
</head>
<body>
  <section class="profile">
    ${avatarHTML}
    <h1 class="profile__name">${esc(name)}</h1>
${bio ? `    <p class="profile__bio">${esc(bio)}</p>\n` : ''}  </section>

  <ul class="links">
${linksHTML}
  </ul>

  <footer class="footer">
    <a class="footer__link" href="https://kntic.ai">Powered by KNTIC Links</a>
  </footer>
</body>
</html>
`;
}

/**
 * links deploy --self — Build a self-contained static HTML page.
 */

import { mkdirSync, writeFileSync, copyFileSync, existsSync, statSync } from 'node:fs';
import { resolve, dirname, basename, join } from 'node:path';
import chalk from 'chalk';
import { findConfig, readConfig } from '../config.js';
import { generatePage } from '../generator.js';

export function registerDeploy(program) {
  program
    .command('deploy')
    .description('Build and deploy the link page')
    .option('--self', 'Generate a self-contained static HTML page')
    .option('--out <dir>', 'Output directory', './dist')
    .option('--open', 'Open the generated page in a browser after build')
    .action(async (opts) => {
      if (!opts.self) {
        console.log(
          chalk.yellow('Usage: links deploy --self [--out <dir>] [--open]'),
        );
        console.log('Other deploy targets are not yet implemented.');
        process.exitCode = 1;
        return;
      }

      // 1. Locate and read config
      let configPath;
      try {
        configPath = findConfig();
      } catch (err) {
        console.error(chalk.red(`✗ ${err.message}`));
        process.exitCode = 1;
        return;
      }

      let config;
      try {
        config = readConfig(configPath);
      } catch (err) {
        console.error(chalk.red(`✗ ${err.message}`));
        process.exitCode = 1;
        return;
      }

      const configDir = dirname(configPath);

      // 2. Generate HTML
      let html;
      try {
        html = generatePage(config, { configDir });
      } catch (err) {
        console.error(chalk.red(`✗ Build failed: ${err.message}`));
        process.exitCode = 1;
        return;
      }

      // 3. Write output
      const outDir = resolve(opts.out);
      mkdirSync(outDir, { recursive: true });

      const outFile = join(outDir, 'index.html');
      writeFileSync(outFile, html, 'utf8');

      // 4. Copy avatar as fallback asset (if it's a local file)
      if (config.avatar && config.avatar.trim().length > 0) {
        const avatarSrc = resolve(configDir, config.avatar);
        if (existsSync(avatarSrc)) {
          try {
            const avatarDest = join(outDir, basename(config.avatar));
            copyFileSync(avatarSrc, avatarDest);
          } catch {
            // non-fatal — avatar is already inlined
          }
        }
      }

      // 5. Summary
      const size = statSync(outFile).size;
      const sizeStr = size < 1024
        ? `${size} B`
        : `${(size / 1024).toFixed(1)} KB`;

      console.log(chalk.green(`✓ Built to ${outFile}`) + chalk.dim(` (${sizeStr})`));

      // 6. Optionally open in browser
      if (opts.open) {
        try {
          const open = (await import('open')).default;
          await open(outFile);
        } catch {
          console.log(chalk.yellow('⚠ Could not open browser automatically.'));
        }
      }
    });
}
